package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testNewBuilder_ReturnsNewGsonBuilderWithThisInstance() {
    Gson gson = new Gson();
    GsonBuilder builder = gson.newBuilder();
    assertNotNull(builder, "GsonBuilder should not be null");
    // Using reflection to verify the Gson instance inside GsonBuilder
    try {
      Field gsonField = null;
      Class<?> clazz = builder.getClass();
      // Search for the field holding the Gson instance in GsonBuilder class hierarchy
      while (clazz != null) {
        Field[] fields = clazz.getDeclaredFields();
        for (Field field : fields) {
          if (field.getType() == Gson.class) {
            gsonField = field;
            break;
          }
        }
        if (gsonField != null) {
          break;
        }
        clazz = clazz.getSuperclass();
      }
      // GsonBuilder does not hold a direct Gson field, but it holds a Gson instance in a field named "gson"
      // If not found by type, try by name
      if (gsonField == null) {
        clazz = builder.getClass();
        while (clazz != null) {
          try {
            gsonField = clazz.getDeclaredField("gson");
            if (gsonField.getType() == Gson.class) {
              break;
            } else {
              gsonField = null;
            }
          } catch (NoSuchFieldException e) {
            // ignore and continue
          }
          clazz = clazz.getSuperclass();
        }
      }
      assertNotNull(gsonField, "Field of type Gson not found in GsonBuilder class hierarchy");
      gsonField.setAccessible(true);
      Object innerGson = gsonField.get(builder);
      assertSame(gson, innerGson, "GsonBuilder should be created with the original Gson instance");
    } catch (IllegalAccessException e) {
      fail("Reflection failed to access Gson field in GsonBuilder: " + e.getMessage());
    }
  }
}
